ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?full_name ?name ?version WHERE {
  ?editorsoftwareprograms a :EditorSoftwarePrograms .
  ?software_programs a :Software_Programs .
  ?editorsoftwareprograms p:hasSoftware_Programs ?software_programs .
  ?editors a :Editors .
  ?editorsoftwareprograms p:hasEditors ?editors .
  ?editors p:name ?full_name .
  ?software_programs p:name ?name .
  ?software_programs p:version ?version .
} }
  collective: { SELECT ?name ?version WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSoftware_Programs ?child ; p:hasEditors ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  ?child p:version ?version .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Editors } }
  FILTER(?nf = ?total)
} }
}

